BEGIN
    --//-- Insert 
    if coalesce(OLD.change_doc_no::text, '') = '' and (NEW.change_doc_no IS NOT NULL AND NEW.change_doc_no::text <> '') then
        if pka.auto_entry then 
            NEW.entry_date := statement_timestamp();
            NEW.entry_id := current_setting('app.login_id', true);
            NEW.entry_br := current_setting('app.login_br', true);
            NEW.change_status := '2'; -- 2-รออนุมัติ
        end if;
    end if;

    --//-- Default 
    if coalesce(NEW.loan_installment::text, '') = '' then NEW.loan_installment := 0;end if;

RETURN NEW;
end
